public void KPMGCommon_initInvoiceObservation(KPMGCommon_InvoiceObservation _invoiceObservation = "")
{

    QueryRun localQR = new QueryRun(this.queryRun().query());
    CustInvoiceTable localInvoiceTable;
    ;
    while (localQR.next())
    {
        localInvoiceTable = localQR.get(tableNum(CustInvoiceTable));
        localInvoiceTable.KPMGCommon_InvoiceObservation = _invoiceObservation;
        this.UpdateInvoiceObservation(localInvoiceTable);
     }
}

public void UpdateInvoiceObservation(CustInvoiceTable custInvoiceTableObservation)
{

    ttsbegin;
    custInvoiceTableObservation.selectForUpdate(true);
    custInvoiceTableObservation.doupdate();
    ttscommit;
}
